import axios from 'axios';
import config from './config';

/**
 * FIXED API Service
 * - SKU validation before API calls
 * - No frontend recalculation of bill amounts
 */

const api = axios.create({
  baseURL: config.API_BASE_URL,
  headers: {
    'Content-Type': 'application/json'
  },
  timeout: 10000
});

api.interceptors.request.use(
  (config) => {
    console.log(`API Request: ${config.method.toUpperCase()} ${config.url}`);
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

api.interceptors.response.use(
  (response) => {
    return response;
  },
  (error) => {
    console.error('API Error:', error.response?.data || error.message);
    return Promise.reject(error);
  }
);

/**
 * Validate SKU format before API call
 */
const validateSKU = (sku) => {
  if (!sku || typeof sku !== 'string') {
    throw new Error('SKU must be a non-empty string');
  }

  const trimmedSKU = sku.trim();

  if (trimmedSKU.length === 0) {
    throw new Error('SKU cannot be empty');
  }

  if (trimmedSKU.length > 50) {
    throw new Error('SKU too long (max 50 characters)');
  }

  // Only allow alphanumeric and common separators
  if (!/^[A-Z0-9\-_]+$/i.test(trimmedSKU)) {
    throw new Error('SKU contains invalid characters');
  }

  return trimmedSKU.toUpperCase();
};

/**
 * Product API Services
 */
export const productService = {
  /**
   * Get product by SKU with validation
   */
  getProductBySKU: async (productId) => {
    try {
      const normalizedSKU = validateSKU(productId);
      const response = await api.get(`/products/${normalizedSKU}`);
      return response.data;
    } catch (error) {
      if (error.message.includes('SKU')) {
        throw { message: error.message };
      }
      throw error.response?.data || { message: 'Failed to fetch product' };
    }
  },

  getAllProducts: async (filters = {}) => {
    try {
      const response = await api.get('/products', { params: filters });
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Failed to fetch products' };
    }
  }
};

/**
 * Bill API Services
 * CRITICAL: Uses backend calculations ONLY
 */
export const billService = {
  createBill: async (billData) => {
    try {
      const response = await api.post('/bills', billData);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Failed to create bill' };
    }
  },

  getBillById: async (billId) => {
    try {
      const response = await api.get(`/bills/${billId}`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Failed to fetch bill' };
    }
  }
};

/**
 * PDF API Services
 */
export const pdfService = {
  getPDFUrl: (billId) => {
    return `${config.API_BASE_URL}/pdf/${billId}`;
  },

  downloadPDF: async (billId) => {
    try {
      const response = await api.get(`/pdf/${billId}`, {
        responseType: 'blob'
      });

      const blob = new Blob([response.data], { type: 'application/pdf' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `${billId}.pdf`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);

      return { success: true };
    } catch (error) {
      throw error.response?.data || { message: 'Failed to download PDF' };
    }
  }
};

export default api;
